import { useState, useRef, useCallback, useEffect } from "react";
import ReactMarkdown from "react-markdown";
import remarkGfm from "remark-gfm";
import { getApiBase } from '../../utils/platform';
import usePortfolioContext from "../../hooks/usePortfolioContext";

/* ============================================================================
   CLAUDE CODE — Chat Interface
   Terminal-style chat to Claude (Anthropic API) via /api/claude/chat
   SSE streaming, markdown rendering, pin-gated access
   ============================================================================ */

const PIN_CODE = "1121";

/* ── Lightweight Markdown code block renderer ─────────────────────────────── */
function MarkdownRenderer({ content }) {
  return (
    <ReactMarkdown
      remarkPlugins={[remarkGfm]}
      components={{
        code({ node, inline, className, children, ...props }) {
          const match = /language-(\w+)/.exec(className || "");
          if (!inline && (match || String(children).includes("\n"))) {
            return (
              <div style={{
                position: "relative",
                margin: "8px 0",
                borderRadius: 10,
                overflow: "hidden",
                border: "1px solid rgba(48,54,61,0.6)",
              }}>
                {match && (
                  <div style={{
                    padding: "4px 10px",
                    fontSize: 10,
                    fontWeight: 600,
                    color: "#8B949E",
                    background: "rgba(22,27,34,0.8)",
                    borderBottom: "1px solid rgba(48,54,61,0.4)",
                    textTransform: "uppercase",
                    letterSpacing: "0.5px",
                  }}>
                    {match[1]}
                  </div>
                )}
                <pre style={{
                  margin: 0,
                  padding: "12px 14px",
                  background: "rgba(13,17,23,0.9)",
                  fontSize: 13,
                  lineHeight: 1.5,
                  overflowX: "auto",
                  fontFamily: "'JetBrains Mono', monospace",
                  color: "#E6EDF3",
                }}>
                  <code {...props}>{children}</code>
                </pre>
              </div>
            );
          }
          return (
            <code
              style={{
                padding: "2px 6px",
                borderRadius: 6,
                background: "rgba(110,118,129,0.2)",
                fontSize: "0.9em",
                fontFamily: "'JetBrains Mono', monospace",
                color: "#E6EDF3",
              }}
              {...props}
            >
              {children}
            </code>
          );
        },
        p({ children }) {
          return <p style={{ margin: "6px 0", lineHeight: 1.7 }}>{children}</p>;
        },
        ul({ children }) {
          return <ul style={{ margin: "6px 0", paddingLeft: 20 }}>{children}</ul>;
        },
        ol({ children }) {
          return <ol style={{ margin: "6px 0", paddingLeft: 20 }}>{children}</ol>;
        },
        li({ children }) {
          return <li style={{ marginBottom: 4, lineHeight: 1.6 }}>{children}</li>;
        },
        h1({ children }) {
          return <h1 style={{ fontSize: 18, fontWeight: 700, margin: "12px 0 6px", color: "#E6EDF3" }}>{children}</h1>;
        },
        h2({ children }) {
          return <h2 style={{ fontSize: 16, fontWeight: 700, margin: "10px 0 5px", color: "#E6EDF3" }}>{children}</h2>;
        },
        h3({ children }) {
          return <h3 style={{ fontSize: 14, fontWeight: 600, margin: "8px 0 4px", color: "#E6EDF3" }}>{children}</h3>;
        },
        blockquote({ children }) {
          return (
            <blockquote style={{
              borderLeft: "3px solid #60A5FA",
              paddingLeft: 12,
              margin: "8px 0",
              color: "#8B949E",
            }}>
              {children}
            </blockquote>
          );
        },
        a({ href, children }) {
          return (
            <a href={href} target="_blank" rel="noopener noreferrer"
              style={{ color: "#60A5FA", textDecoration: "underline", textUnderlineOffset: 2 }}>
              {children}
            </a>
          );
        },
        table({ children }) {
          return (
            <div style={{ overflowX: "auto", margin: "8px 0" }}>
              <table style={{
                borderCollapse: "collapse",
                fontSize: 13,
                fontFamily: "'JetBrains Mono', monospace",
                width: "100%",
              }}>
                {children}
              </table>
            </div>
          );
        },
        th({ children }) {
          return (
            <th style={{
              padding: "6px 10px",
              borderBottom: "2px solid #30363D",
              textAlign: "left",
              fontSize: 11,
              color: "#8B949E",
              fontWeight: 600,
            }}>
              {children}
            </th>
          );
        },
        td({ children }) {
          return (
            <td style={{
              padding: "5px 10px",
              borderBottom: "1px solid rgba(48,54,61,0.4)",
            }}>
              {children}
            </td>
          );
        },
        hr() {
          return <hr style={{ border: "none", borderTop: "1px solid #30363D", margin: "12px 0" }} />;
        },
      }}
    >
      {content}
    </ReactMarkdown>
  );
}

/* ── Pin Gate ──────────────────────────────────────────────────────────────── */
function PinGate({ onUnlock }) {
  const [pin, setPin] = useState("");
  const [error, setError] = useState(false);
  const [shake, setShake] = useState(false);
  const inputRef = useRef(null);

  useEffect(() => {
    inputRef.current?.focus();
  }, []);

  const submit = () => {
    if (pin === PIN_CODE) {
      onUnlock();
    } else {
      setError(true);
      setShake(true);
      setTimeout(() => setShake(false), 500);
      setPin("");
      inputRef.current?.focus();
    }
  };

  return (
    <div style={{
      display: "flex",
      flexDirection: "column",
      alignItems: "center",
      justifyContent: "center",
      height: "100%",
      minHeight: "50vh",
      padding: "20px 16px",
      fontFamily: "'JetBrains Mono', monospace",
    }}>
      <div style={{
        padding: "clamp(24px, 5vw, 40px) clamp(20px, 4vw, 48px)",
        borderRadius: 14,
        background: "#161B22",
        border: "1px solid #30363D",
        textAlign: "center",
        boxShadow: "0 20px 60px rgba(0,0,0,0.4)",
        animation: shake ? "shake 0.4s ease-in-out" : undefined,
        width: "100%",
        maxWidth: 340,
      }}>
        {/* Lock icon */}
        <div style={{
          width: 48, height: 48, borderRadius: 14,
          background: "rgba(88,166,255,0.1)",
          border: "1px solid rgba(88,166,255,0.2)",
          display: "flex", alignItems: "center", justifyContent: "center",
          margin: "0 auto 16px",
          fontSize: 22,
        }}>
          <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="#60A5FA" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
            <rect x="3" y="11" width="18" height="11" rx="2" ry="2" />
            <path d="M7 11V7a5 5 0 0 1 10 0v4" />
          </svg>
        </div>

        <div style={{ fontSize: 16, fontWeight: 700, color: "#E6EDF3", marginBottom: 8 }}>
          Claude Code Access
        </div>
        <div style={{ fontSize: 11, color: "#8B949E", marginBottom: 20 }}>
          Enter PIN to continue
        </div>

        <div style={{ display: "flex", gap: 8, justifyContent: "center" }}>
          <input
            ref={inputRef}
            type="password"
            inputMode="numeric"
            maxLength={8}
            value={pin}
            onChange={(e) => { setPin(e.target.value); setError(false); }}
            onKeyDown={(e) => { if (e.key === "Enter") submit(); }}
            placeholder="----"
            style={{
              width: "100%",
              maxWidth: 140,
              padding: "12px 14px",
              borderRadius: 10,
              fontSize: 18,
              fontFamily: "'JetBrains Mono', monospace",
              background: "rgba(0,0,0,0.4)",
              border: `1px solid ${error ? "#EF4444" : "#30363D"}`,
              color: "#E6EDF3",
              outline: "none",
              textAlign: "center",
              letterSpacing: "4px",
              transition: "border-color 0.25s",
              minHeight: 44,
            }}
          />
          <button
            onClick={submit}
            style={{
              padding: "12px 20px",
              borderRadius: 10,
              fontSize: 13,
              fontWeight: 600,
              fontFamily: "'Plus Jakarta Sans', sans-serif",
              background: "rgba(88,166,255,0.15)",
              border: "1px solid rgba(88,166,255,0.3)",
              color: "#60A5FA",
              cursor: "pointer",
              transition: "all 0.25s",
              minHeight: 44,
            }}
            onMouseEnter={(e) => { e.target.style.background = "rgba(88,166,255,0.25)"; }}
            onMouseLeave={(e) => { e.target.style.background = "rgba(88,166,255,0.15)"; }}
          >
            Unlock
          </button>
        </div>

        {error && (
          <div style={{ marginTop: 12, fontSize: 11, color: "#EF4444" }}>
            Invalid PIN. Try again.
          </div>
        )}
      </div>

      {/* Shake animation */}
      <style>{`
        @keyframes shake {
          0%, 100% { transform: translateX(0); }
          20% { transform: translateX(-8px); }
          40% { transform: translateX(8px); }
          60% { transform: translateX(-6px); }
          80% { transform: translateX(6px); }
        }
      `}</style>
    </div>
  );
}

/* ── Main Chat Component ──────────────────────────────────────────────────── */
function ClaudeChatInterface() {
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState("");
  const [loading, setLoading] = useState(false);
  const [streamText, setStreamText] = useState("");
  const scrollRef = useRef(null);
  const inputRef = useRef(null);
  const abortRef = useRef(null);
  const { contextEnabled, setContextEnabled, refreshContext, contextLoading } = usePortfolioContext();

  const scrollBottom = () => {
    setTimeout(() => scrollRef.current?.scrollTo({
      top: scrollRef.current.scrollHeight,
      behavior: "smooth",
    }), 80);
  };

  /* ── Send message with SSE streaming ────────────────────── */
  const send = useCallback(async () => {
    const text = input.trim();
    if (!text || loading) return;

    setInput("");
    setMessages((prev) => [...prev, { role: "user", text, ts: Date.now() }]);
    setLoading(true);
    setStreamText("");
    scrollBottom();

    const ctrl = new AbortController();
    abortRef.current = ctrl;

    // Build message with portfolio context if enabled
    let messageToSend = text;
    if (contextEnabled) {
      const ctx = await refreshContext();
      if (ctx) {
        messageToSend = ctx + "\n\n" + text;
      }
    }

    try {
      const resp = await fetch(`${getApiBase()}/claude/chat`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          message: messageToSend,
          history: messages.map((m) => ({
            role: m.role === "error" ? "assistant" : m.role,
            content: m.text,
          })),
        }),
        signal: ctrl.signal,
      });

      if (!resp.ok) {
        const errText = await resp.text();
        throw new Error(errText || `HTTP ${resp.status}`);
      }

      const contentType = resp.headers.get("content-type") || "";

      if (contentType.includes("text/event-stream") || contentType.includes("text/plain")) {
        /* ── SSE streaming path ─── */
        const reader = resp.body.getReader();
        const decoder = new TextDecoder();
        let buffer = "";
        let accumulated = "";

        while (true) {
          const { done, value } = await reader.read();
          if (done) break;
          buffer += decoder.decode(value, { stream: true });

          const lines = buffer.split("\n");
          buffer = lines.pop() || "";

          for (const line of lines) {
            if (line.startsWith("data: ")) {
              const payload = line.slice(6);
              if (payload === "[DONE]") continue;
              try {
                const evt = JSON.parse(payload);
                if (evt.type === "content_block_delta" && evt.delta?.text) {
                  accumulated += evt.delta.text;
                  setStreamText(accumulated);
                  scrollBottom();
                } else if (evt.type === "text" || evt.text) {
                  accumulated += (evt.text || "");
                  setStreamText(accumulated);
                  scrollBottom();
                } else if (evt.type === "done" || evt.type === "message_stop") {
                  if (evt.final) accumulated = evt.final;
                } else if (evt.type === "error") {
                  throw new Error(evt.detail || evt.message || "Stream error");
                } else if (typeof evt === "string") {
                  accumulated += evt;
                  setStreamText(accumulated);
                  scrollBottom();
                }
              } catch (parseErr) {
                // If it's not JSON, treat the raw data line as text
                if (parseErr instanceof SyntaxError) {
                  accumulated += payload;
                  setStreamText(accumulated);
                  scrollBottom();
                } else if (!parseErr.message?.includes("JSON")) {
                  throw parseErr;
                }
              }
            } else if (line.trim() && !line.startsWith(":") && !line.startsWith("event:")) {
              // Plain text streaming (non-SSE)
              accumulated += line + "\n";
              setStreamText(accumulated);
              scrollBottom();
            }
          }
        }

        // Finalize
        const finalText = accumulated.trim() || "(no response)";
        setMessages((prev) => [
          ...prev,
          { role: "assistant", text: finalText, ts: Date.now() },
        ]);
      } else {
        /* ── JSON response path ─── */
        const data = await resp.json();
        const finalText = data.response || data.content || data.message || data.text || data.final || "(no response)";
        setMessages((prev) => [
          ...prev,
          { role: "assistant", text: finalText, ts: Date.now() },
        ]);
      }
    } catch (e) {
      if (e.name === "AbortError") {
        const partial = streamText || "";
        if (partial) {
          setMessages((prev) => [
            ...prev,
            { role: "assistant", text: partial + "\n\n_(cancelled)_", ts: Date.now() },
          ]);
        } else {
          setMessages((prev) => [
            ...prev,
            { role: "error", text: "Request cancelled", ts: Date.now() },
          ]);
        }
      } else {
        setMessages((prev) => [
          ...prev,
          { role: "error", text: e.message || "Request failed", ts: Date.now() },
        ]);
      }
    } finally {
      setLoading(false);
      setStreamText("");
      abortRef.current = null;
      scrollBottom();
      inputRef.current?.focus();
    }
  }, [input, loading, messages, streamText]);

  const cancel = useCallback(() => {
    abortRef.current?.abort();
  }, []);

  const clearChat = () => {
    setMessages([]);
    setStreamText("");
    inputRef.current?.focus();
  };

  /* ── Keyboard shortcut: Ctrl+L to clear ────────────────── */
  useEffect(() => {
    const handler = (e) => {
      if ((e.metaKey || e.ctrlKey) && e.key === "l") {
        e.preventDefault();
        clearChat();
      }
    };
    window.addEventListener("keydown", handler);
    return () => window.removeEventListener("keydown", handler);
  }, []);

  const ts = (d) => {
    const date = new Date(d);
    return date.toLocaleTimeString([], { hour: "2-digit", minute: "2-digit", second: "2-digit" });
  };

  return (
    <div style={{
      display: "flex",
      flexDirection: "column",
      height: "100%",
      fontFamily: "'JetBrains Mono', monospace",
    }}>
      {/* ── Top bar ────────────────────────────────────────── */}
      <div style={{
        display: "flex",
        alignItems: "center",
        gap: 12,
        marginBottom: 8,
        flexWrap: "wrap",
      }}>
        {/* Model badge */}
        <div style={{
          display: "flex",
          alignItems: "center",
          gap: 8,
          padding: "4px 10px",
          borderRadius: 10,
          background: "rgba(88,166,255,0.08)",
          border: "1px solid rgba(88,166,255,0.15)",
        }}>
          <span style={{
            width: 7, height: 7, borderRadius: "50%",
            background: "#22C55E",
            boxShadow: "0 0 6px rgba(63,185,80,0.5)",
          }} />
          <span style={{ fontSize: 10, fontWeight: 700, color: "#60A5FA", letterSpacing: "0.3px" }}>
            Claude Opus 4.6
          </span>
        </div>

        <span style={{ fontSize: 10, color: "#8B949E" }}>
          Anthropic API
        </span>

        <div style={{ flex: 1 }} />

        {/* Portfolio context toggle */}
        <button
          onClick={() => setContextEnabled(prev => !prev)}
          title={contextEnabled ? "Portfolio context active -- click to disable" : "Portfolio context disabled -- click to enable"}
          style={{
            display: "flex", alignItems: "center", gap: 4,
            padding: "4px 10px", borderRadius: 10, fontSize: 10, fontWeight: 600,
            fontFamily: "'Plus Jakarta Sans', sans-serif", cursor: "pointer",
            background: contextEnabled ? "rgba(63,185,80,0.1)" : "rgba(255,255,255,0.04)",
            border: `1px solid ${contextEnabled ? "rgba(63,185,80,0.25)" : "#30363D"}`,
            color: contextEnabled ? "#22C55E" : "#8B949E",
            transition: "all 0.15s",
          }}
        >
          <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
            <path d="M21 12V7H5a2 2 0 0 1 0-4h14v4" />
            <path d="M3 5v14a2 2 0 0 0 2 2h16v-5" />
            <path d="M18 12a2 2 0 0 0 0 4h4v-4Z" />
          </svg>
          Portfolio
          {contextEnabled && (
            <span style={{
              width: 6, height: 6, borderRadius: "50%",
              background: contextLoading ? "#F59E0B" : "#22C55E",
              flexShrink: 0,
              animation: contextLoading ? "claudePulse 1s infinite" : undefined,
            }} />
          )}
        </button>

        <span style={{ fontSize: 10, color: "#8B949E", fontFamily: "'Plus Jakarta Sans', sans-serif" }}>
          Ctrl+L clear
        </span>

        <button
          onClick={clearChat}
          disabled={messages.length === 0 && !loading}
          style={{
            fontSize: 10,
            padding: "4px 12px",
            borderRadius: 10,
            background: "rgba(255,255,255,0.04)",
            border: "1px solid #30363D",
            color: "#E6EDF3",
            cursor: "pointer",
            opacity: messages.length > 0 || loading ? 1 : 0.3,
            fontFamily: "'Plus Jakarta Sans', sans-serif",
            fontWeight: 600,
            transition: "all 0.15s",
          }}
          onMouseEnter={(e) => { if (messages.length) e.target.style.background = "rgba(255,255,255,0.08)"; }}
          onMouseLeave={(e) => { e.target.style.background = "rgba(255,255,255,0.04)"; }}
        >
          Clear
        </button>
      </div>

      {/* ── Messages area ──────────────────────────────────── */}
      <div
        ref={scrollRef}
        style={{
          flex: 1,
          overflowY: "auto",
          overflowX: "hidden",
          padding: "clamp(8px, 2vw, 14px) clamp(8px, 2vw, 16px)",
          borderRadius: 14,
          background: "rgba(0,0,0,0.35)",
          border: "1px solid #30363D",
          marginBottom: 12,
          WebkitOverflowScrolling: "touch",
        }}
      >
        {/* Empty state */}
        {messages.length === 0 && !loading && (
          <div style={{ textAlign: "center", marginTop: 64 }}>
            <div style={{
              fontSize: 28, opacity: 0.15, fontWeight: 800, marginBottom: 12,
              background: "linear-gradient(135deg, #60A5FA, #22C55E)",
              WebkitBackgroundClip: "text",
              WebkitTextFillColor: "transparent",
            }}>
              claude_
            </div>
            <div style={{ fontSize: 13, color: "#8B949E", marginBottom: 16, fontFamily: "'Plus Jakarta Sans', sans-serif" }}>
              Ask Claude anything. Code, architecture, debugging, analysis.
            </div>
            <div style={{ display: "flex", flexDirection: "column", gap: 8, alignItems: "center" }}>
              {[
                "Explain how the AA Core backtest engine works",
                "Write a Python FastAPI endpoint for portfolio risk",
                "Review this code for performance issues",
              ].map((hint) => (
                <button
                  key={hint}
                  onClick={() => { setInput(hint); inputRef.current?.focus(); }}
                  style={{
                    fontSize: 11,
                    padding: "6px 14px",
                    borderRadius: 10,
                    background: "rgba(255,255,255,0.03)",
                    border: "1px solid rgba(48,54,61,0.5)",
                    color: "#8B949E",
                    cursor: "pointer",
                    fontFamily: "'JetBrains Mono', monospace",
                    transition: "all 0.15s",
                    maxWidth: "min(420px, 90vw)",
                  }}
                  onMouseEnter={(e) => {
                    e.target.style.borderColor = "rgba(88,166,255,0.3)";
                    e.target.style.color = "#E6EDF3";
                  }}
                  onMouseLeave={(e) => {
                    e.target.style.borderColor = "rgba(48,54,61,0.5)";
                    e.target.style.color = "#8B949E";
                  }}
                >
                  {hint}
                </button>
              ))}
            </div>
          </div>
        )}

        {/* Message list */}
        {messages.map((m, i) => (
          <div key={i} style={{ marginBottom: 16 }}>
            <div style={{
              padding: "10px 14px",
              borderRadius: 14,
              maxWidth: "95%",
              marginLeft: m.role === "user" ? "auto" : 0,
              background: m.role === "user"
                ? "rgba(88,166,255,0.08)"
                : m.role === "error"
                  ? "rgba(248,81,73,0.08)"
                  : "rgba(255,255,255,0.02)",
              border: `1px solid ${
                m.role === "user"
                  ? "rgba(88,166,255,0.15)"
                  : m.role === "error"
                    ? "rgba(248,81,73,0.2)"
                    : "rgba(48,54,61,0.5)"
              }`,
            }}>
              {/* Message header */}
              <div style={{
                display: "flex",
                justifyContent: "space-between",
                alignItems: "center",
                marginBottom: 8,
              }}>
                <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                  {m.role === "user" ? (
                    <span style={{
                      fontSize: 10, fontWeight: 700, color: "#60A5FA",
                      textTransform: "uppercase", letterSpacing: "0.5px",
                    }}>
                      You
                    </span>
                  ) : m.role === "error" ? (
                    <span style={{
                      fontSize: 10, fontWeight: 700, color: "#EF4444",
                      textTransform: "uppercase", letterSpacing: "0.5px",
                    }}>
                      Error
                    </span>
                  ) : (
                    <>
                      <span style={{
                        fontSize: 10, fontWeight: 700, color: "#22C55E",
                        textTransform: "uppercase", letterSpacing: "0.5px",
                      }}>
                        Claude
                      </span>
                      <span style={{
                        fontSize: 10, color: "#8B949E",
                        padding: "1px 5px", borderRadius: 6,
                        background: "rgba(255,255,255,0.04)",
                      }}>
                        opus-4.6
                      </span>
                    </>
                  )}
                </div>
                <span style={{ fontSize: 10, color: "#8B949E" }}>
                  {ts(m.ts)}
                </span>
              </div>

              {/* Message content */}
              {m.role === "user" ? (
                <div style={{
                  fontSize: 13,
                  whiteSpace: "pre-wrap",
                  wordBreak: "break-word",
                  lineHeight: 1.6,
                  color: "#E6EDF3",
                }}>
                  {m.text}
                </div>
              ) : (
                <div style={{
                  fontSize: 13,
                  wordBreak: "break-word",
                  lineHeight: 1.6,
                  color: m.role === "error" ? "#EF4444" : "#E6EDF3",
                }}>
                  <MarkdownRenderer content={m.text} />
                </div>
              )}
            </div>
          </div>
        ))}

        {/* Streaming response */}
        {loading && streamText && (
          <div style={{ marginBottom: 16 }}>
            <div style={{
              padding: "10px 14px",
              borderRadius: 14,
              maxWidth: "95%",
              background: "rgba(255,255,255,0.02)",
              border: "1px solid rgba(48,54,61,0.5)",
            }}>
              <div style={{
                display: "flex",
                alignItems: "center",
                gap: 8,
                marginBottom: 8,
              }}>
                <span style={{
                  fontSize: 10, fontWeight: 700, color: "#22C55E",
                  textTransform: "uppercase", letterSpacing: "0.5px",
                }}>
                  Claude
                </span>
                <span style={{
                  fontSize: 10, color: "#60A5FA",
                  padding: "1px 5px", borderRadius: 6,
                  background: "rgba(88,166,255,0.1)",
                  animation: "pulse 2s infinite",
                }}>
                  streaming...
                </span>
              </div>
              <div style={{ fontSize: 13, wordBreak: "break-word", lineHeight: 1.6, color: "#E6EDF3" }}>
                <MarkdownRenderer content={streamText} />
              </div>
            </div>
          </div>
        )}

        {/* Typing indicator (no stream text yet) */}
        {loading && !streamText && (
          <div style={{
            padding: "12px 16px",
            display: "flex",
            alignItems: "center",
            gap: 12,
            background: "rgba(88,166,255,0.04)",
            borderRadius: 14,
            border: "1px solid rgba(88,166,255,0.1)",
          }}>
            <span style={{ display: "flex", gap: 4 }}>
              {[0, 1, 2].map((i) => (
                <span
                  key={i}
                  style={{
                    width: 6, height: 6,
                    borderRadius: "50%",
                    background: "#60A5FA",
                    display: "inline-block",
                    animation: `claudePulse 1.4s ease-in-out ${i * 0.2}s infinite`,
                    opacity: 0.5,
                  }}
                />
              ))}
            </span>
            <span style={{ fontSize: 11, color: "#8B949E" }}>
              Claude is thinking...
            </span>
            <button
              onClick={cancel}
              style={{
                marginLeft: "auto",
                fontSize: 10,
                padding: "3px 10px",
                borderRadius: 6,
                background: "rgba(255,255,255,0.04)",
                border: "1px solid #30363D",
                color: "#8B949E",
                cursor: "pointer",
                fontFamily: "'Plus Jakarta Sans', sans-serif",
              }}
            >
              Cancel
            </button>
          </div>
        )}
      </div>

      {/* ── Input bar ──────────────────────────────────────── */}
      <div style={{ display: "flex", gap: 8, flexShrink: 0 }}>
        <div style={{
          flex: 1,
          position: "relative",
          display: "flex",
          alignItems: "center",
          minWidth: 0,
        }}>
          <span style={{
            position: "absolute",
            left: 14,
            fontSize: 13,
            color: "#22C55E",
            fontWeight: 700,
            pointerEvents: "none",
            opacity: 0.6,
          }}>
            &gt;
          </span>
          <input
            ref={inputRef}
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => {
              if (e.key === "Enter" && !e.shiftKey) {
                e.preventDefault();
                send();
              }
            }}
            placeholder="Ask Claude..."
            disabled={loading}
            autoComplete="off"
            style={{
              width: "100%",
              padding: "12px 14px 12px 28px",
              borderRadius: 14,
              fontSize: 13,
              fontFamily: "'JetBrains Mono', monospace",
              background: "rgba(0,0,0,0.3)",
              border: "1px solid #30363D",
              color: "#E6EDF3",
              outline: "none",
              transition: "border-color 0.25s",
              minHeight: 44,
            }}
            onFocus={(e) => { e.target.style.borderColor = "rgba(88,166,255,0.4)"; }}
            onBlur={(e) => { e.target.style.borderColor = "#30363D"; }}
          />
        </div>
        <button
          onClick={loading ? cancel : send}
          disabled={!loading && !input.trim()}
          style={{
            padding: "12px clamp(12px, 3vw, 24px)",
            borderRadius: 14,
            fontSize: 13,
            fontWeight: 700,
            fontFamily: "'Plus Jakarta Sans', sans-serif",
            background: loading
              ? "rgba(248,81,73,0.12)"
              : input.trim()
                ? "rgba(63,185,80,0.12)"
                : "rgba(255,255,255,0.04)",
            border: `1px solid ${
              loading
                ? "rgba(248,81,73,0.25)"
                : input.trim()
                  ? "rgba(63,185,80,0.25)"
                  : "#30363D"
            }`,
            color: loading ? "#EF4444" : input.trim() ? "#22C55E" : "#8B949E",
            cursor: !loading && !input.trim() ? "default" : "pointer",
            transition: "all 0.15s",
            minWidth: 56,
            minHeight: 44,
            flexShrink: 0,
          }}
        >
          {loading ? "Stop" : "Send"}
        </button>
      </div>

      {/* Keyframe animations */}
      <style>{`
        @keyframes claudePulse {
          0%, 80%, 100% { opacity: 0.2; transform: scale(0.8); }
          40% { opacity: 0.8; transform: scale(1.1); }
        }
        @keyframes pulse {
          0%, 100% { opacity: 0.6; }
          50% { opacity: 1; }
        }
      `}</style>
    </div>
  );
}

/* ============================================================================
   PAGE: Claude Chat (pin-gated)
   ============================================================================ */
export default function ClaudeChat() {
  const [unlocked, setUnlocked] = useState(() => {
    return sessionStorage.getItem("claude_chat_unlocked") === "true";
  });

  const handleUnlock = () => {
    setUnlocked(true);
    sessionStorage.setItem("claude_chat_unlocked", "true");
  };

  return (
    <div role="main" aria-label="Claude Code Chat" data-mode="operator" style={{
      fontFamily: "'Plus Jakarta Sans', sans-serif",
      height: "100%",
      display: "flex",
      flexDirection: "column",
      overflow: "hidden",
      padding: "clamp(8px, 2vw, 0px)",
    }}>
      {/* Header */}
      <div className="v2-pagehead" style={{ flexShrink: 0 }}>
        <div style={{ minWidth: 0 }}>
          <h1 className="v2-h1" style={{ display: "flex", alignItems: "center", gap: 12, flexWrap: "wrap" }}>
            Claude Code
            <span style={{
              fontSize: 10,
              fontWeight: 600,
              padding: "3px 8px",
              borderRadius: 6,
              background: "rgba(88,166,255,0.1)",
              border: "1px solid rgba(88,166,255,0.2)",
              color: "#60A5FA",
              fontFamily: "'JetBrains Mono', monospace",
            }}>
              Opus 4.6
            </span>
          </h1>
          <div className="v2-muted" style={{ fontSize: 11 }}>
            Chat with Claude via Anthropic API
          </div>
        </div>
      </div>

      {/* Content */}
      <div style={{
        flex: 1,
        minHeight: 0,
        display: "flex",
        flexDirection: "column",
        overflow: "hidden",
      }}>
        {unlocked ? (
          <div className="v2-card" style={{
            flex: 1,
            display: "flex",
            flexDirection: "column",
            minHeight: 0,
          }}>
            <ClaudeChatInterface />
          </div>
        ) : (
          <PinGate onUnlock={handleUnlock} />
        )}
      </div>
    </div>
  );
}
